// --- Callback trampoline pools ---
//
// The C callback types carry no user-data pointer, so every distinct Rust
// closure handed to openDAQ needs its own native entry point.  A fixed pool
// of pre-compiled trampolines routes each call, via its baked-in slot index,
// to the closure registry in crate::callbacks.
pub const TRAMPOLINE_POOL_SIZE: usize = 256;
unsafe extern "C" fn event_trampoline_0(sender: *mut daqBaseObject, args: *mut daqBaseObject) { crate::callbacks::dispatch_event(0, sender, args); }
unsafe extern "C" fn event_trampoline_1(sender: *mut daqBaseObject, args: *mut daqBaseObject) { crate::callbacks::dispatch_event(1, sender, args); }
